// auth.js - Servicio de autenticación
// Solo conecta login y registro con el backend

// ============================================
// CONFIGURACIÓN BASE
// ============================================

const BASE_URL = 'http://localhost:8080/api'; // Cambiar según puerto del backend

// ============================================
// UTILIDADES
// ============================================

const getHeaders = (requiresAuth = false) => {
  const headers = {
    'Content-Type': 'application/json',
  };
  
  if (requiresAuth) {
    const token = localStorage.getItem('auth_token');
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }
  }
  
  return headers;
};

const handleResponse = async (response) => {
  let data;
  try {
    data = await response.json();
  } catch (e) {
    data = {};
  }
  
  if (!response.ok) {
    throw {
      status: response.status,
      message: data.message || data.error || 'Error en la petición',
    };
  }
  
  return data;
};

// ============================================
// REGISTRO - Endpoint: /api/auth/register
// ============================================

/**
 * Registrar un nuevo usuario
 * @param {Object} userData - Datos del usuario { nombre, email, password, telefono, documento }
 * @returns {Promise}
 */
export const register = async (userData) => {
  try {
    const url = `${BASE_URL}/auth/register`;
    
    // Mapear datos del frontend al backend (RegisterRequest)
    const body = {
      name: userData.nombre,        // RegisterRequest.name
      email: userData.email,        // RegisterRequest.email
      password: userData.password,  // RegisterRequest.password
      phone: userData.telefono || '' // RegisterRequest.phone (opcional)
    };
    
    const params = {
      method: 'POST',
      headers: getHeaders(false),
      body: JSON.stringify(body)
    };
    
    const response = await fetch(url, params);
    const result = await handleResponse(response);
    
    return { 
      success: true, 
      message: 'Usuario registrado exitosamente',
      data: result 
    };
  } catch (error) {
    console.error('Error en registro:', error);
    return { 
      success: false, 
      message: error.message || 'Error al registrar usuario' 
    };
  }
};

// ============================================
// LOGIN - Endpoint: /api/auth/login
// ============================================

/**
 * Iniciar sesión
 * @param {string} email - Correo electrónico
 * @param {string} password - Contraseña
 * @returns {Promise}
 */
export const login = async (email, password) => {
  try {
    const url = `${BASE_URL}/auth/login`;
    
    const body = {
      email: email,
      password: password
    };
    
    const params = {
      method: 'POST',
      headers: getHeaders(false),
      body: JSON.stringify(body)
    };
    
    const response = await fetch(url, params);
    const result = await handleResponse(response);
    
    // AuthResponse: { token, userId, name, level }
    if (result.token) {
      // Guardar token
      localStorage.setItem('auth_token', result.token);
      
      // Guardar datos del usuario (estructura que espera el frontend)
      localStorage.setItem('user', JSON.stringify({
        id: result.userId,
        nombre: result.name,
        email: email,
        nivel: result.level || 'Bronce',
        puntos: 0
      }));
    }
    
    return { 
      success: true, 
      user: getCurrentUser(),
      token: result.token 
    };
  } catch (error) {
    console.error('Error en login:', error);
    return { 
      success: false, 
      message: error.message || 'Credenciales incorrectas' 
    };
  }
};

// ============================================
// LOGOUT
// ============================================

/**
 * Cerrar sesión
 */
export const logout = () => {
  localStorage.removeItem('auth_token');
  localStorage.removeItem('user');
  return { success: true };
};

// ============================================
// UTILIDADES DE SESIÓN
// ============================================

/**
 * Obtener usuario actual (de localStorage)
 */
export const getCurrentUser = () => {
  const user = localStorage.getItem('user');
  return user ? JSON.parse(user) : null;
};

/**
 * Verificar si hay sesión activa
 */
export const isAuthenticated = () => {
  return !!localStorage.getItem('auth_token');
};

/**
 * Obtener token (para otras peticiones futuras)
 */
export const getToken = () => {
  return localStorage.getItem('auth_token');
};
